def minInsertions(self, s: str) -> int:
    stack = []
    count = 0
    for c in s:
        if c == '(':
            stack.append(c)
        elif c == ')':
            if len(stack) == 0:
            count += 1
            stack.append(c)
        else:
            stack.pop()
    return count

